use std::collections::BTreeMap;
use std::convert::From;

struct TimeSeriesData {
    measurements: Vec<(i64, f64)>
}

impl From<Vec<(i64, f64)>> for TimeSeriesData {
    fn from(measurements: Vec<(i64, f64)>) -> Self {
        TimeSeriesData { measurements }
    }
}

fn aggregate_records(input_data: &TimeSeriesData) -> BTreeMap<i64, f64> {
    let mut accumulator = BTreeMap::new();

    for &(timestamp, value) in &input_data.measurements {
        if let Some(existing_value) = accumulator.get_mut(&timestamp) {
            *existing_value += value;
        } else {
            accumulator.insert(timestamp, value);
        }
    }

    accumulator
}

fn main() {
    let raw_measurements: Vec<(i64, f64)> = vec![
        (1001, 5.2),
        (1002, -1.1),
        (1001, 3.8),
        (1003, 9.0),
        (1002, 4.5)
    ];

    let data = TimeSeriesData::from(raw_measurements);
    let final_map = aggregate_records(&data);

    for (timestamp, total) in final_map {
        println!("Time Index: {}", timestamp); 
        println!("Accumulated Value: {:.2}", total);
    }
}

use std::collections::BTreeMap;
use std::collections::HashMap;

struct RequestRecord {
    client_id: String,
    payload: Vec<u8>,
}

fn process_requests(records: Vec<RequestRecord>) -> (HashMap<String, Vec<u8>>, BTreeMap<usize, String>)
{
    let mut request_map: HashMap<String, Vec<u8>> = HashMap::new();
    let mut ordered_lookup: BTreeMap<usize, String> = BTreeMap::new();

    for (index, record) in records.into_iter().enumerate() {
        request_map.entry(record.client_id.clone()).or_insert(Vec::new()).extend_from_slice(&record.payload);
        ordered_lookup.insert(index + 1, format!("Processed for client: {}", record.client_id));
    }

    (request_map, ordered_lookup)
}

use std::collections::BTreeMap;
use std::iter::IntoIterator;

struct SourceMap { 
    mapping: BTreeMap<String, String> 
}

impl SourceMap {
    fn new() -> Self {
        SourceMap { mapping: BTreeMap::new() }
    }

    fn add_entry<I>(&mut self, items: I) 
    where 
        I: IntoIterator<Item = (String, String)>,
    {
        for (key, value) in items.into_iter() {
            self.mapping.insert(key, value);
        }
    }

    fn get_sorted_mappings(&self) -> std::collections::BTreeMap<String, String> {
        self.mapping.clone()
    }
}

fn main() {
    let mut map_generator = SourceMap::new();

    let form_data: Vec<(String, String)> = vec![
        ("endpoint_id".to_string(), "req_123".to_string()),
        ("user_session".to_string(), "sess_abc".to_string()),
        ("cache_key".to_string(), "data_xyz".to_string()),
    ];

    map_generator.add_entry(form_data);

    let final_index = map_generator.get_sorted_mappings();
    println!("Generated Index (Sorted):");
    for (key, value) in final_index.iter() {
        println!("  {}: {}", key, value);
    }
}

use std::collections::BTreeMap;

struct SensorReading {
    id: u32,
    value: f32,
}

fn process_readings(readings: Vec<SensorReading>) -> BTreeMap<u32, f32> {
    let mut map = BTreeMap::new();
    for reading in readings.into_iter() {
        map.insert(reading.id, reading.value);
    }
    map
}

fn main() {
    let raw_data = vec![ 
        SensorReading { id: 1024, value: 3.14f32 }, 
        SensorReading { id: 512, value: 1.0f32 }, 
        SensorReading { id: 2048, value: 9.99f32 }
    ];

    let state_map = process_readings(raw_data);

    println!("Stored sensor states:");
    for (id, value) in state_map.iter() {
        println!("Register ID: {}", id); 
        println!("tValue: {:.2}", value);
    }
}

use std::collections::BTreeMap;

struct PacketRecord {
    source_ip: String,
    destination_ip: String,
    length: usize,
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let raw_packets = vec![
        PacketRecord { source_ip: "192.168.1.10".to_string(), destination_ip: "255.255.255.255".to_string(), length: 64 },
        PacketRecord { source_ip: "192.168.1.20".to_string(), destination_ip: "192.168.1.1".to_string(), length: 120 },
        PacketRecord { source_ip: "192.168.1.10".to_string(), destination_ip: "8.8.8.8".to_string(), length: 50 },
        PacketRecord { source_ip: "192.168.1.20".to_string(), destination_ip: "192.168.1.1".to_string(), length: 120 },
        PacketRecord { source_ip: "172.0.0.5".to_string(), destination_ip: "192.168.1.1".to_string(), length: 80 },
    ];

    let mut ip_counter: BTreeMap<String, u32> = raw_packets.iter()
        .fold(BTreeMap::new(), |mut acc, packet| {
            *acc.entry(packet.source_ip.clone()).or_insert(0) += 1;
            acc
        });

    println!("n--- Unique Source IP Counts ---n");
    for (ip, count) in &ip_counter {
        println!("IP: {}", ip);
        println!(" -> Count: {}", count);
    }

    Ok(())
}
